import{_ as e,o as l,c as i,a9 as r}from"./chunks/framework.STMWz9Nm.js";const p=JSON.parse('{"title":"ZAB与一致性基础","description":"","frontmatter":{},"headers":[],"relativePath":"语言/java/14-ZooKeeper学习/03-ZAB与一致性基础.md","filePath":"语言/java/14-ZooKeeper学习/03-ZAB与一致性基础.md","lastUpdated":1776149370000}'),o={name:"语言/java/14-ZooKeeper学习/03-ZAB与一致性基础.md"};function t(h,a,_,n,d,s){return l(),i("div",null,[...a[0]||(a[0]=[r('<h1 id="zab与一致性基础" tabindex="-1">ZAB与一致性基础 <a class="header-anchor" href="#zab与一致性基础" aria-label="Permalink to “ZAB与一致性基础”">​</a></h1><h2 id="_1-这是什么" tabindex="-1">1. 这是什么 <a class="header-anchor" href="#_1-这是什么" aria-label="Permalink to “1. 这是什么”">​</a></h2><p>ZAB 是 ZooKeeper 的原子广播协议，用于保证写入顺序和集群一致性。<br> 它是 ZooKeeper 能作为协调服务使用的重要基础。</p><h2 id="_2-为什么重要" tabindex="-1">2. 为什么重要 <a class="header-anchor" href="#_2-为什么重要" aria-label="Permalink to “2. 为什么重要”">​</a></h2><p>如果不了解一致性基础，就很难理解 ZooKeeper 为什么能做配置、注册和选主。<br> 也很难理解它在高可用和故障恢复中的行为边界。</p><h2 id="_3-核心内容" tabindex="-1">3. 核心内容 <a class="header-anchor" href="#_3-核心内容" aria-label="Permalink to “3. 核心内容”">​</a></h2><ul><li>原子广播基本认知</li><li>leader / follower 角色</li><li>写请求顺序保证</li><li>崩溃恢复基础认知</li><li>一致性与可用性的权衡</li></ul><h2 id="_4-学习重点" tabindex="-1">4. 学习重点 <a class="header-anchor" href="#_4-学习重点" aria-label="Permalink to “4. 学习重点”">​</a></h2><ul><li>理解 ZooKeeper 更偏向一致性</li><li>理解写入顺序对于协调系统的重要性</li><li>理解协议层是上层能力可信的基础</li></ul><h2 id="_5-常见问题" tabindex="-1">5. 常见问题 <a class="header-anchor" href="#_5-常见问题" aria-label="Permalink to “5. 常见问题”">​</a></h2><ul><li>把 ZooKeeper 当成普通缓存系统</li><li>不了解一致性选择背后的代价</li><li>只知选主，不知协议基础</li></ul><h2 id="_6-练习建议" tabindex="-1">6. 练习建议 <a class="header-anchor" href="#_6-练习建议" aria-label="Permalink to “6. 练习建议”">​</a></h2><ul><li>画一张 leader / follower 协作图</li><li>总结 ZooKeeper 为什么适合做协调</li><li>比较强一致协调和高吞吐存储的差异</li></ul><h2 id="_7-自测问题" tabindex="-1">7. 自测问题 <a class="header-anchor" href="#_7-自测问题" aria-label="Permalink to “7. 自测问题”">​</a></h2><ul><li>ZAB 主要解决什么问题</li><li>为什么 ZooKeeper 更强调一致性</li><li>协调系统为什么很依赖写入顺序保证</li></ul>',15)])])}const b=e(o,[["render",t]]);export{p as __pageData,b as default};
